import type { IncomingMessage, ServerResponse } from "node:http"
import { parseCookieHeader, serializeCookie } from "../cookies.js"
import type { NewtonAuth } from "../core.js"
import type { AuthRequestData, AuthResult, CookieInstruction, NewtonUser } from "../models.js"

export interface NodeHandlerOptions {
  onUnauthenticated?: (req: IncomingMessage, res: ServerResponse, result: AuthResult) => void
  onUnauthorized?: (req: IncomingMessage, res: ServerResponse, result: AuthResult) => void
  /**
   * Gate on authentication alone. When true, an authenticated but unauthorized
   * user is allowed through instead of being rejected with 403 — for apps that
   * manage their own authorization and use this SDK purely to identify the user.
   * Unauthenticated users are still rejected with 401.
   */
  authenticatedOnly?: boolean
}

type NodeHandler = (req: IncomingMessage, res: ServerResponse) => void | Promise<void>

const userStore = new WeakMap<IncomingMessage, NewtonUser>()

/** Returns the authenticated user attached by requireAuth. */
export function getUser(req: IncomingMessage): NewtonUser | undefined {
  return userStore.get(req)
}

function firstForwardedValue(header: string | string[] | undefined): string {
  if (!header) return ""
  const value = Array.isArray(header) ? header[0] ?? "" : header
  return (value.split(",")[0] ?? "").trim()
}

export function requestData(req: IncomingMessage): AuthRequestData {
  const url = new URL(req.url ?? "/", "http://placeholder")
  const query: Record<string, string> = {}
  url.searchParams.forEach((value, key) => {
    query[key] = value
  })
  const encrypted = (req.socket as { encrypted?: boolean }).encrypted === true
  return {
    path: url.pathname,
    query,
    cookies: parseCookieHeader(req.headers.cookie),
    host: firstForwardedValue(req.headers["x-forwarded-host"]) || req.headers.host || "localhost",
    proto: firstForwardedValue(req.headers["x-forwarded-proto"]) || (encrypted ? "https" : "http"),
  }
}

export function applyCookies(res: ServerResponse, cookies: CookieInstruction[]): void {
  const existing = res.getHeader("set-cookie")
  const headers: string[] = Array.isArray(existing) ? existing.map(String) : existing ? [String(existing)] : []
  headers.push(...cookies.map(serializeCookie))
  res.setHeader("set-cookie", headers)
}

function respond(res: ServerResponse, status: number, message: string): void {
  res.statusCode = status
  res.setHeader("content-type", "text/plain; charset=utf-8")
  res.end(message)
}

function redirect(res: ServerResponse, location: string): void {
  res.statusCode = 302
  res.setHeader("location", location)
  res.end()
}

export function createNodeHandlers(auth: NewtonAuth) {
  const loginHandler = async (req: IncomingMessage, res: ServerResponse): Promise<void> => {
    const data = requestData(req)
    const next = data.query["next"] || "/"
    try {
      auth.validateLoginRedirectTarget(next)
    } catch (err) {
      respond(res, 400, err instanceof Error ? err.message : "invalid login redirect target")
      return
    }
    try {
      const { location, stateCookie } = auth.buildLoginRedirect(data, next)
      applyCookies(res, [stateCookie])
      redirect(res, location)
    } catch {
      respond(res, 500, "failed to start login")
    }
  }

  const callbackHandler = async (req: IncomingMessage, res: ServerResponse): Promise<void> => {
    const data = requestData(req)
    try {
      const result = await auth.handleCallback(data)
      if (!result.authenticated) {
        applyCookies(res, [result.clearStateCookie, ...auth.clearSessionCookies()])
        respond(res, 401, "account_not_found")
        return
      }
      applyCookies(res, [result.sessionCookie!, result.clearStateCookie])
      redirect(res, result.redirectUri)
    } catch {
      applyCookies(res, auth.clearSessionCookies())
      respond(res, 400, "invalid auth callback")
    }
  }

  const requireAuth = (handler: NodeHandler, opts: NodeHandlerOptions = {}): NodeHandler => {
    return async (req, res) => {
      let result: AuthResult
      try {
        result = await auth.authenticate(requestData(req))
      } catch {
        respond(res, 500, "authentication failed")
        return
      }
      if (!result.authenticated) {
        if (result.shouldClearSession) applyCookies(res, auth.clearSessionCookies())
        const onUnauthenticated = opts.onUnauthenticated ?? ((rq, rs) => respond(rs, 401, "authentication required"))
        onUnauthenticated(req, res, result)
        return
      }
      if (!result.authorized && !opts.authenticatedOnly) {
        if (result.shouldClearSession) applyCookies(res, auth.clearSessionCookies())
        const onUnauthorized = opts.onUnauthorized ?? ((rq, rs) => respond(rs, 403, "forbidden"))
        onUnauthorized(req, res, result)
        return
      }
      userStore.set(req, result.user!)
      await handler(req, res)
    }
  }

  const middleware = (next: NodeHandler): NodeHandler => {
    return async (req, res) => {
      const path = new URL(req.url ?? "/", "http://placeholder").pathname
      if (path === auth.config.loginPath) {
        await loginHandler(req, res)
        return
      }
      if (path === auth.config.callbackPath) {
        await callbackHandler(req, res)
        return
      }
      await next(req, res)
    }
  }

  return { loginHandler, callbackHandler, requireAuth, middleware, getUser }
}
